# Function to calculate factorial recursively
proc factorial {n} {
    # Check if the input is 0 or 1
    if {$n == 0 || $n == 1} {
        return 1
    } else {
        # Recursive call to calculate factorial
        return [expr $n * [factorial [expr $n - 1]]]
    }
}

# Function to get user input and validate it
proc getUserInput {} {
    set input ""
    while {1} {
        puts "Enter a positive integer to calculate its factorial:"
        set input [gets stdin]
        if {[string is integer -strict $input] && $input >= 0} {
            return $input
        } else {
            puts "Invalid input. Please enter a non-negative integer."
        }
    }
}

# Main execution
proc main {} {
    set number [getUserInput]
    set result [factorial $number]
