Creating a program that generates a random name using a Markov chain involves several steps. Below is a Python implementation that demonstrates how you can achieve this. This program will read a text file containing names, then use a Markov chain to generate new names.

### Step-by-Step Guide

1. **Prepare the Data**: You need a text file with a list of names to train the Markov model.
2. **Build the Markov Model**: Create a transition matrix that captures the probability of moving from one character to another.
3. **Generate Names**: Use the transition matrix to generate new names.

### Python Code

```python
import random
import re

class MarkovNameGenerator:
    def __init__(self, filename):
        self.model = {}
        self.words = self.load_names(filename)
        self.train()

    def load_names(self, filename):
        with open(filename, 'r', encoding='utf-8') as file:
            return file.read().splitlines()

    def train(self):
        for word in self.words:
            # Convert to lowercase and split into characters
            chars = [char for char in word.lower()]
            for i in range(len(chars) - 1):
                if chars[i] not in self.model:
                    self.model[chars[i]] = {}
                if chars[i + 1] not in self.model[chars[i]]:
                    self.model[chars[i]][chars[i + 1]] = 0
                self.model[chars[i]][chars[i + 1]] += 1
            # Add a special end character
            if chars[-1] not in self.model:
                self.model[chars[-1]] = {}
            self.model[chars[-1]]['END'] = self.model.get(chars[-1], {}).get('END', 0) + 1

    def generate_name(self, max_length=10):
        if not self.model:
            return ""

        current_char = random.choice(list(self.model.keys()))
        name = current_char

        while len(name) < max_length:
            if current_char not in self.model:
                break
            next_char = random.choices(list(self.model[current_char].keys()), weights=list(self.model[current_char].values()))[0]
            if next_char == 'END':
                break
            name += next_char
            current_char = next_char

        return name

# Example usage
if __name__ == "__main__":
    generator = MarkovNameGenerator("names.txt")

